        "opts": [
          "none",
          "anticoagulation_or_antiplatelet",
          "bisphosphonate",
          "head_neck_radiation"
        ],
        "labels_cn": [
          "无",
          "抗凝/抗血小板药物",
          "双膦酸盐",
          "头颈部放疗史"
        ],
        "labels_en": [
          "none",
          "anticoagulation_or_antiplatelet",
          "bisphosphonate",
          "head_neck_radiation"
        ],
        "required": true,
        "note_cn": "双膦酸盐或头颈部放疗史者颌骨手术前须专科评估（参照RF-013/RF-014逻辑）",
