        "labels_en": [
          "1_to_2_mild",
          "3_to_5_moderate",
          "6_or_more_oligodontia"
        ],
        "required": true,
        "note_cn": "少牙畸形（6颗或以上先天缺牙）须排除外胚层发育不良综合征，转儿科或遗传科",
